const record = $('Webhook Trigger').first().json.body.record;
const submissionType = record.submission_type;
const receiptUrl = record.receipt_url;
const barcodeUrl = record.barcode_url;
const expiryUrl = record.expiry_url;

const hasReceipt = !!(receiptUrl && receiptUrl !== '' && receiptUrl !== null);
const hasBarcode = !!(barcodeUrl && barcodeUrl !== '' && barcodeUrl !== null);
const hasExpiry = !!(expiryUrl && expiryUrl !== '' && expiryUrl !== null);

const MESSAGES = {
  MISSING_RECEIPT: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!',
  BARCODE_ONLY: 'Hola 👋, solo subiste el código de barras, no el ticket completo. ¡Inténtalo de nuevo!',
  NO_RECEIPT_ONLY_PRODUCTS: 'Hola 👋, vemos los productos, pero necesitamos también el ticket de compra para validar el rescate. Sin ticket no podemos otorgar los puntos. ¡Gracias!',
  MISSING_BARCODE: 'Hola 👋, la fecha de caducidad y código de barras deben ser bien visibles. ¡Gracias!',
  MISSING_EXPIRY: 'Hola 👋, además del código de barras, necesitamos foto clara de la fecha de caducidad corta. ¡Gracias!'
};

if (submissionType === 1) {
  if (!hasReceipt) {
    return [{ json: { imagesValid: false, reason: 'MISSING_RECEIPT', rejection_message: MESSAGES.MISSING_RECEIPT, processing_stage: 'missing_images' } }];
  }
}

if (submissionType === 2) {
  if (!hasReceipt && hasBarcode && !hasExpiry) {
    return [{ json: { imagesValid: false, reason: 'BARCODE_ONLY', rejection_message: MESSAGES.BARCODE_ONLY, processing_stage: 'missing_images' } }];
  }
  if (!hasReceipt && (hasBarcode || hasExpiry)) {
    return [{ json: { imagesValid: false, reason: 'NO_RECEIPT_ONLY_PRODUCTS', rejection_message: MESSAGES.NO_RECEIPT_ONLY_PRODUCTS, processing_stage: 'missing_images' } }];
  }
  if (!hasReceipt) {
    return [{ json: { imagesValid: false, reason: 'MISSING_RECEIPT', rejection_message: MESSAGES.MISSING_RECEIPT, processing_stage: 'missing_images' } }];
  }
  if (!hasBarcode) {
    return [{ json: { imagesValid: false, reason: 'MISSING_BARCODE', rejection_message: MESSAGES.MISSING_BARCODE, processing_stage: 'missing_images' } }];
  }
  if (!hasExpiry) {
    return [{ json: { imagesValid: false, reason: 'MISSING_EXPIRY', rejection_message: MESSAGES.MISSING_EXPIRY, processing_stage: 'missing_images' } }];
  }
}

return [{ json: { imagesValid: true, submissionType } }];

