parameters.jsCode:
const item = $input.first().json;

if (item.error) {
  return [{ json: {
    extractionError: true,
    reason: 'RECEIPT_READ_ERROR',
    rejection_message: 'Hola 👋, no pudimos leer tu ticket. Por favor sube una foto más clara. ¡Gracias!',
    processing_stage: 'gemini_extraction_error'
  }}];
}

let raw;
try {
  raw = item.candidates[0].content.parts[0].text;
} catch(e) {
  return [{ json: {
    extractionError: true,
    reason: 'RECEIPT_READ_ERROR',
    rejection_message: 'Hola 👋, no pudimos leer tu ticket. Por favor sube una foto más clara. ¡Gracias!',
    processing_stage: 'gemini_extraction_error'
  }}];
}

const cleaned = raw.replace(/```json|```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  return [{ json: {
    extractionError: true,
    reason: 'RECEIPT_READ_ERROR',
    rejection_message: 'Hola 👋, no pudimos leer tu ticket. Por favor sube una foto más clara. ¡Gracias!',
    processing_stage: 'gemini_extraction_error'
  }}];
}

let receiptDate = parsed.receipt_date || '';
if (receiptDate.includes('/')) {
  const parts = receiptDate.split('/');
  if (parts.length === 3 && parts[0].length === 2) {
    receiptDate = `${parts[2]}-${parts[1]}-${parts[0]}`;
  }
}

const receiptTime = parsed.receipt_time || '00:00:00';

let receiptDatetimeUTC = null;
try {
  const localDt = new Date(`${receiptDate}T${receiptTime}`);
  if (!isNaN(localDt.getTime())) {
    receiptDatetimeUTC = new Date(localDt.getTime() - (2 * 60 * 60 * 1000)).toISOString();
  }
} catch(e) {}

return [{ json: {
  extractionError: false,
  receipt_date: receiptDate,
  receipt_time: receiptTime,
  receipt_datetime_utc: receiptDatetimeUTC,
  store_name: parsed.store_name || null,
  store_location: parsed.store_location || null,
  store_country: parsed.store_country || null,
  receipt_number: parsed.receipt_number || null,
  total_amount: parsed.total_amount || null,
  currency: parsed.currency || null,
  line_items: parsed.line_items || [],
  confidence: parsed.confidence || 0
}}];

const ticket = $('Webhook Trigger').first().json.body.record;
const extracted = $('Normalize And Parse Receipt').first().json;

const MESSAGES = {
  OUTSIDE_24H: 'Hola 👋, el ticket debe enviarse dentro de las 24h posteriores a la compra. ¡Gracias!',
  FUTURE_DATE: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!',
  INCOMPLETE_TICKET: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!',
  INVALID_STORE: 'Hola 👋, solo aceptamos tickets de supermercados. ¡Gracias!'
};

const invalidStores = [
  'restaurant', 'restaurante', 'farmacia', 'pharmacy', 'gasolinera',
  'gas station', 'bar ', 'cafe ', 'cafeteria', 'mcdonald', 'burger',
  'pizz', 'kebab', 'panaderia', 'pasteleria', 'drogueria', 'brico',
  'ferreteria', 'zara', 'primark', 'decathlon', 'ikea', 'leroy',
  'fnac', 'mediamarkt', 'worten', 'optica', 'clinica', 'freshly',
  'delivery', 'takeaway', 'bistro', 'tapas', 'cerveceria', 'heladeria',
  'sushi', 'wok', 'thai', 'el corte ingles'
];

const storeName = (extracted.store_name || '').toLowerCase();

if (!storeName || storeName === 'null' || storeName === '') {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_1_logic' } }];
}

if (invalidStores.some(s => storeName.includes(s))) {
  return [{ json: { approved: false, reason: 'INVALID_STORE', rejection_message: MESSAGES.INVALID_STORE, processing_stage: 'flow_1_logic' } }];
}

if (!extracted.receipt_date || extracted.receipt_date === 'null') {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_1_logic' } }];
}

if (!extracted.total_amount || extracted.total_amount === 0) {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_1_logic' } }];
}

if (!extracted.receipt_datetime_utc) {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_1_logic' } }];
}

const submittedAt = new Date(ticket.submitted_at);
const receiptUTC = new Date(extracted.receipt_datetime_utc);
const diffHours = (submittedAt - receiptUTC) / 3600000;

if (diffHours < -2) {
  return [{ json: { approved: false, reason: 'FUTURE_DATE', rejection_message: MESSAGES.FUTURE_DATE, processing_stage: 'flow_1_logic' } }];
}

if (diffHours > 24) {
  return [{ json: { approved: false, reason: 'OUTSIDE_24H', rejection_message: MESSAGES.OUTSIDE_24H, processing_stage: 'flow_1_logic' } }];
}

return [{ json: {
  approved: true,
  points_awarded: 2,
  flow: 1,
  store_name: extracted.store_name,
  receipt_date: extracted.receipt_date,
  hours_since_purchase: Math.round(diffHours * 10) / 10,
  processing_stage: 'flow_1_approved'
}}];

let barcodeData = { barcode_gtin: null, barcode_confidence: 0, tampering_detected: false };
let expiryData = { expiry_date: null, expiry_confidence: 0, tampering_detected: false };

try {
  const bt = $('Extract Barcode').first().json.candidates[0].content.parts[0].text;
  barcodeData = JSON.parse(bt.replace(/```json|```/g,'').trim());
} catch(e) {}

try {
  const et = $('Extract Expiry').first().json.candidates[0].content.parts[0].text;
  expiryData = JSON.parse(et.replace(/```json|```/g,'').trim());
} catch(e) {}

let expiryDate = expiryData.expiry_date || null;
if (expiryDate && expiryDate.includes('/')) {
  const parts = expiryDate.split('/');
  if (parts.length === 3 && parts[0].length === 2) {
    expiryDate = `${parts[2]}-${parts[1]}-${parts[0]}`;
  }
}

return [{ json: {
  barcode_gtin: barcodeData.barcode_gtin || null,
  barcode_confidence: barcodeData.barcode_confidence || 0,
  barcode_tampering: barcodeData.tampering_detected || false,
  expiry_date: expiryDate,
  expiry_confidence: expiryData.expiry_confidence || 0,
  expiry_tampering: expiryData.tampering_detected || false
}}];

const ticket = $('Webhook Trigger').first().json.body.record;
const extracted = $('Normalize And Parse Receipt').first().json;
const product = $('Merge Product Data').first().json;

const MESSAGES = {
  OUTSIDE_24H: 'Hola 👋, el ticket debe enviarse dentro de las 24h posteriores a la compra. ¡Gracias!',
  ALREADY_EXPIRED: 'Hola 👋, No Podemos Dar Puntos Por Productos Que Hayas Comprado Ya Caducados ¡Gracias!',
  EXPIRY_OUT_OF_RANGE: 'Hola 👋, los puntos son solo para productos que caducan en menos de 5 días de la compra. ¡Gracias!',
  PRODUCT_NOT_ON_RECEIPT: 'Hola 👋, hemos revisado tu ticket y no encontramos el producto indicado en él. Por ahora, no podemos validarlo. ¡Gracias igualmente por participar!',
  INCOMPLETE_TICKET: 'Hola 👋, necesitamos ver el ticket completo y fecha de compra. ¡Gracias!',
  INVALID_STORE: 'Hola 👋, solo aceptamos tickets de supermercados. ¡Gracias!'
};

const invalidStores = [
  'restaurant', 'restaurante', 'farmacia', 'pharmacy', 'gasolinera',
  'bar ', 'cafe ', 'cafeteria', 'mcdonald', 'burger', 'pizz', 'kebab',
  'panaderia', 'zara', 'primark', 'decathlon', 'ikea', 'el corte ingles'
];

const storeName = (extracted.store_name || '').toLowerCase();
if (!storeName || storeName === 'null') {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_2_logic' } }];
}
if (invalidStores.some(s => storeName.includes(s))) {
  return [{ json: { approved: false, reason: 'INVALID_STORE', rejection_message: MESSAGES.INVALID_STORE, processing_stage: 'flow_2_logic' } }];
}

if (!extracted.receipt_datetime_utc) {
  return [{ json: { approved: false, reason: 'INCOMPLETE_TICKET', rejection_message: MESSAGES.INCOMPLETE_TICKET, processing_stage: 'flow_2_logic' } }];
}

const submittedAt = new Date(ticket.submitted_at);
const receiptUTC = new Date(extracted.receipt_datetime_utc);
const diffHours = (submittedAt - receiptUTC) / 3600000;

if (diffHours > 24) {
  return [{ json: { approved: false, reason: 'OUTSIDE_24H', rejection_message: MESSAGES.OUTSIDE_24H, processing_stage: 'flow_2_logic' } }];
}

if (!product.expiry_date) {
  return [{ json: { approved: false, reason: 'MISSING_EXPIRY', rejection_message: 'Hola 👋, además del código de barras, necesitamos foto clara de la fecha de caducidad corta. ¡Gracias!', processing_stage: 'flow_2_logic' } }];
}

const receiptDate = new Date(extracted.receipt_date + 'T00:00:00');
const expiryDate = new Date(product.expiry_date + 'T00:00:00');
const daysToExpiry = (expiryDate - receiptDate) / 86400000;

if (daysToExpiry < 0) {
  return [{ json: { approved: false, reason: 'ALREADY_EXPIRED', rejection_message: MESSAGES.ALREADY_EXPIRED, processing_stage: 'flow_2_logic' } }];
}

if (daysToExpiry >= 5) {
  return [{ json: { approved: false, reason: 'EXPIRY_OUT_OF_RANGE', rejection_message: MESSAGES.EXPIRY_OUT_OF_RANGE, processing_stage: 'flow_2_logic' } }];
}

function similarity(s1, s2) {
  if (!s1 || !s2) return 0;
  const w1 = s1.toLowerCase().split(' ');
  const w2 = s2.toLowerCase().split(' ');
  return w1.filter(w => w2.includes(w)).length / Math.max(w1.length, w2.length);
}

const hasGTIN = product.barcode_gtin && product.barcode_gtin.trim() !== '';
let matchedProduct = 'fresh_produce_no_barcode';

if (hasGTIN) {
  let productNames = [];
  try {
    const off = $('GTIN Lookup OpenFoodFacts').first().json;
    if (off.status === 1 && off.product) {
      if (off.product.product_name) productNames.push(off.product.product_name);
      if (off.product.brands) productNames.push(off.product.brands);
    }
  } catch(e) {}
  try {
    const upc = $('GTIN Lookup UPCItemDB').first().json;
    if (upc.items && upc.items[0]) {
      if (upc.items[0].title) productNames.push(upc.items[0].title);
      if (upc.items[0].brand) productNames.push(upc.items[0].brand);
    }
  } catch(e) {}
  productNames = productNames.filter(Boolean);
  const items = extracted.line_items || [];
  const match = items.find(i => productNames.some(n => similarity(i.name, n) >= 0.75));
  if (!match && productNames.length > 0) {
    return [{ json: { approved: false, reason: 'PRODUCT_NOT_ON_RECEIPT', rejection_message: MESSAGES.PRODUCT_NOT_ON_RECEIPT, processing_stage: 'flow_2_logic' } }];
  }
  if (match) matchedProduct = match.name;
}

const pointsMap = { 0: 5, 1: 4, 2: 3, 3: 2, 4: 1 };
const pts = pointsMap[Math.round(daysToExpiry)] ?? 1;

return [{ json: {
  approved: true,
  points_awarded: pts,
  flow: 2,
  matched_product: matchedProduct,
  days_to_expiry: Math.round(daysToExpiry),
  store_name: extracted.store_name,
  receipt_date: extracted.receipt_date,
  hours_since_purchase: Math.round(diffHours * 10) / 10,
  processing_stage: 'flow_2_approved'
}}];

const ticket = $('Webhook Trigger').first().json.body.record;
const extracted = $('Normalize And Parse Receipt').isExecuted
  ? $('Normalize And Parse Receipt').first().json
  : {};

const sources = ['Flow 1 Logic','Flow 2 Logic','Reject - Low Confidence','Check Required Images','Normalize And Parse Receipt'];

let result = null;
for (const src of sources) {
  try {
    const n = $(src);
    if (n.isExecuted) { result = n.first().json; break; }
  } catch(e) {}
}

if (!result) {
  result = { approved: false, reason: 'UNKNOWN_ERROR', rejection_message: 'Hola 👋, no pudimos procesar tu ticket. Por favor inténtalo de nuevo. ¡Gracias!', processing_stage: 'unknown' };
}

const isApproved = result.approved === true;

return [{ json: {
  timestamp: new Date().toISOString(),
  ticket_id: ticket.id || '',
  user_id: ticket.user_id || '',
  firebase_user_id: ticket.firebase_user_id || '',
  submission_type: ticket.submission_type || '',
  status: isApproved ? 'approved' : 'rejected',
  rejection_reason: isApproved ? '' : (result.reason || 'UNKNOWN'),
  rejection_message: isApproved ? '' : (result.rejection_message || ''),
  points_awarded: isApproved ? (result.points_awarded || 0) : 0,
  flow: result.flow || '',
  store_name: extracted.store_name || result.store_name || '',
  receipt_date: extracted.receipt_date || result.receipt_date || '',
  hours_since_purchase: result.hours_since_purchase || '',
  days_to_expiry: result.days_to_expiry || '',
  matched_product: result.matched_product || '',
  gemini_confidence: extracted.confidence || '',
  receipt_url: ticket.receipt_url || '',
  processing_stage: result.processing_stage || 'unknown'
}}];
